    [Fact]
    public void WFiltro_FinanceiroEqualsIntMinValue_ShouldNotAddParameterOrWhereClause()
    {
        // Arrange
        var filtro = new FilterTipoCompromisso
        {
            Financeiro = int.MinValue
        };
        // Act
        var result = _serviceS.WFiltroTipoCompromisso(filtro);
        // Assert
        result.Should().NotBeNull();
        result.Value.parametros.Should().NotContain(p => p.ParameterName.Contains(DBTipoCompromissoDicInfo.Financeiro));
        result.Value.where.Should().NotContain(DBTipoCompromissoDicInfo.Financeiro);
    }

    [Fact]
    public void WFiltro_FinanceiroHasValidValue_ShouldAddParameterAndWhereClause()
    {
        // Arrange
        var FinanceiroValue = 1;
        var filtro = new FilterTipoCompromisso
        {
            Financeiro = FinanceiroValue,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroTipoCompromisso(filtro);
        // Assert
        result.Should().NotBeNull();
        // Check parameter
        var FinanceiroParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBTipoCompromissoDicInfo.Financeiro}");
        FinanceiroParameter.Should().NotBeNull();
        FinanceiroParameter.Value.Should().Be(FinanceiroValue);
        // Check where clause
        result.Value.where.Should().Contain($"[{DBTipoCompromissoDicInfo.PTabelaNome}].[{DBTipoCompromissoDicInfo.Financeiro}] = @{DBTipoCompromissoDicInfo.Financeiro}");
    }

    [Fact]
    public void WFiltro_FinanceiroWithDifferentValues_ShouldAddCorrectParameterValue()
    {
        // Arrange & Act & Assert for Financeiro = 0 (typically female)
        var filtroFemale = new FilterTipoCompromisso
        {
            Financeiro = 0
        };
        var resultFemale = _serviceS.WFiltroTipoCompromisso(filtroFemale);
        resultFemale.Should().NotBeNull();
        var femaleParam = resultFemale.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBTipoCompromissoDicInfo.Financeiro}");
        femaleParam.Should().NotBeNull();
        femaleParam.Value.Should().Be(0);
        // Arrange & Act & Assert for Financeiro = 1 (typically male)
        var filtroMale = new FilterTipoCompromisso
        {
            Financeiro = 1
        };
        var resultMale = _serviceS.WFiltroTipoCompromisso(filtroMale);
        resultMale.Should().NotBeNull();
        var maleParam = resultMale.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBTipoCompromissoDicInfo.Financeiro}");
        maleParam.Should().NotBeNull();
        maleParam.Value.Should().Be(1);
    }

